import { useRef } from "react";
import { FaCheck } from "react-icons/fa";
import { validaCampo } from "../../../Controller/funcoesVariadas";
//import {validaCampoFormulario} from "../../../Controller/funcoesVariadas";

function NovoCliente(){

    const nome = useRef('');
    const cpf = useRef('');
    const dataDeNascimento = useRef('');
    const logradouro = useRef('');
    const numero = useRef('');
    const complemento = useRef('');
    const observacaoEndereco = useRef('');
    const bairro = useRef('');
    const cidade = useRef('');
    const telefone = useRef('');
    const telefoneRecado = useRef('');
    const email = useRef('');
    const observacaoCliente = useRef('');

    function manipuladorDeFormulario(campo){
        /*
        let item = campo.target;
        
        switch(item.id){
            case 'nome': 
                this.setState({nome: Cliente.formataNome(item.value)});
                break;
            case 'cpf': 
                this.setState({cpf: Cliente.formataCPF(item.value)});
                break;
            case 'dataDeNascimento': 
                this.setState({dataDeNascimento: item.value});
                break;
            case 'logradouro': 
                this.setState({logradouro: Cliente.formataNome(item.value)});
                break;
            case 'numero':  
                this.setState({numero: item.value});
                break;
            case 'complemento': 
                this.setState({complemento: item.value});
                break;
            case 'observacaoEndereco': 
                this.setState({observacaoEndereco: item.value});
                break;
            case 'bairro': 
                this.setState({bairro: Cliente.formataNome(item.value)});
                break;
            case 'cidade': 
                this.setState({cidade: Cliente.formataNome(item.value)});                
                break;
            case 'telefone':
                this.setState({telefone: Cliente.formataTelefone(item.value)});
                break;
            case 'telefoneRecado': 
                this.setState({telefoneRecado: Cliente.formataTelefone(item.value)});
                break;
            case 'email': 
                this.setState({email: item.value});
                break;
            case 'observacaoCliente':
                this.setState({observacaoCliente: item.value});
                break;
            default: return false;
            
        }*/
    }

    function verificadorDeFormulario(campo){
        /*
        let item = campo.target;
        let aprovacao = false;
        switch(item.id){
            case 'nome': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaNome);                          
                break;
            case 'cpf':
                aprovacao = validaCampoFormulario(campo, Cliente.validaCPF);
                break;
            case 'dataDeNascimento':
                aprovacao = validaCampoFormulario(campo, Cliente.validaDataNascimento);
                break;
            case 'logradouro':  
                aprovacao = validaCampoFormulario(campo, Cliente.validaNome);                          
                break;
            case 'numero': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaNumero); 
                break;
            case 'bairro': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaBairro);
                break;
            case 'cidade': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaCidade);         
                break;
            case 'telefone': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaTelefone);
                break;            
            default: return false;            
        }*/
    }

    return(
        <div className="espaco_em_cima container containerForm">
            <fieldset className="fieldset">
                <form>
                    <div>                    
                        <div className="">
                            <p className="letrasVermelhas">* campos obrigatórios</p>
                            <span className="letrasVermelhas campoObrigatorio">*</span>
                            <label className="">Nome</label><br />
                            <div className='naoExibir letrasVermelhas'>
                                Informe nome e sobrenome
                            </div>
                            <input type='text' 
                                className="required" 
                                id='nome' 
                                required 
                                name="nome" 
                                title='Preencha nome e sobrenome'
                                ref={nome} 
                                onBlur={(e) => validaCampo(e.target)}
                                maxLength='100'>   
                            </input>
                            <FaCheck color="green" size="25" className="naoExibir"/>
                        </div>
                        <div className="espacoAntes divFlex espacoDepois">
                            <div className="">
                                <span className="letrasVermelhas campoObrigatorio">*</span>
                                <label className="">CPF ou CNPJ</label>
                                <div className='naoExibir letrasVermelhas'>
                                    Informe cpf ou cnpj do cliente, apenas números
                                </div>
                                <input id='cpf' 
                                    className="required"
                                    ref={cpf} 
                                    required
                                    onBlur={(e) => validaCampo(e.target)}
                                    maxLength='18'>                            
                                </input>
                                <FaCheck color="green" size="25" className="naoExibir"/>
                            </div>
                            <div className="">
                                <span className="letrasVermelhas campoObrigatorio">*</span>
                                <label className="">Data de Nascimento</label>
                                <div className='naoExibir letrasVermelhas'>
                                    Informe a data de nascimento do cliente
                                </div>
                                <input type='date' id='dataDeNascimento' 
                                    ref={dataDeNascimento} 
                                    onBlur={(e) => validaCampo(e.target)}
                                    className="required"
                                    required />
                                <FaCheck color="green" size="25" className="naoExibir"/>
                            </div>
                        </div>
                        
                    </div>
                    <hr className="espaco_em_cima"/>
                    <div>
                        <div className="espacoAntes divFlex espacoDepois">
                            <div className="">
                                <span className="letrasVermelhas campoObrigatorio">*</span>
                                <label className="" >Nome da rua ou avenida</label>
                                <div className='naoExibir letrasVermelhas'>
                                    Informe o nome da rua do cliente
                                </div>
                                <input id='logradouro'  className="required" ref={logradouro} 
                                    required
                                    onBlur={(e) => validaCampo(e.target)}
                                    maxLength='200'>
                                </input>
                                <FaCheck color="green" size="25" className="naoExibir"/>
                            </div>
                            <div className="">
                                <span className="letrasVermelhas campoObrigatorio">*</span>
                                <label className="">Número da Casa</label>
                                <div className='naoExibir letrasVermelhas'>
                                    Informe o número da casa
                                </div>
                                <input id='numero' type="number" required className="required" ref={numero} 
                                    onBlur={(e) => validaCampo(e.target)}>
                                </input>
                                <FaCheck color="green" size="25" className="naoExibir"/>
                            </div>
                        </div>
                        
                        <div className="">
                            <label className="">Complemento</label><br />
                            <input id='complemento' className="required" ref={complemento} maxLength='45'>
                            </input>
                        </div>
                        <div className="divFlex">
                            <label className="">Observação sobre o endereço</label><br />
                            <input id='observacaoEndereco' className="required" ref={observacaoEndereco} maxLength='100'></input>
                        </div>
                        <div className="">
                            <span className="letrasVermelhas campoObrigatorio">*</span>
                            <label className="">Bairro</label><br />
                            <div className='naoExibir letrasVermelhas'>
                                Informe o bairro
                            </div>
                            <input id='bairro' className="required" ref={bairro} 
                                onBlur={(e) => validaCampo(e.target)}
                                maxLength='45'>
                            </input>
                            <FaCheck color="green" size="25" className="naoExibir"/>
                        </div>
                        <div className="">
                            <span className="letrasVermelhas campoObrigatorio">*</span>
                            <label className="">Cidade</label><br />
                            <div className='naoExibir letrasVermelhas'>
                                Informe a cidade
                            </div>
                            <input id='cidade' className="required" ref={cidade} 
                                onBlur={(e) => validaCampo(e.target)}
                                maxLength='100'> 
                            </input>
                            <FaCheck color="green" size="25" className="naoExibir"/>
                        </div>
                    </div>
                    <hr  className="espaco_em_cima"/>
                    <div>
                        <div className="espacoAntes divFlex espacoDepois">
                            <div className="">
                                <span className="letrasVermelhas campoObrigatorio">*</span>
                                <label className="">Telefone</label><br />
                                <div className='naoExibir letrasVermelhas'>
                                    Informe o telefone
                                </div>
                                <input id='telefone' className="required" ref={telefone}
                                    onBlur={(e) => validaCampo(e.target)}
                                    maxLength='50'> 
                                </input>
                                <FaCheck color="green" size="25" className="naoExibir"/>
                            </div>
                            <div className="">
                                <label className="">Telefone de Recado</label><br />
                                <input id='telefoneRecado' className="" ref={telefoneRecado} 
                                    maxLength='50'>
                                </input>
                            </div>
                        </div>
                        
                        <div className="dividirTelaEmDuasDivs">
                            <label className="">Email</label><br />
                            <input id='email'  className="" ref={email} maxLength='100'></input>
                        </div>
                        <div className="espaco_em_cima">
                            <label className="">Observação sobre o cliente</label><br/>
                            <textarea id='observacaoCliente'  className="" ref={observacaoCliente}  maxLength='200'></textarea>
                        </div>
                        <div className="espaco_em_cima flexNaoResponsivo">
                            <div>
                                <button className="div-botao borda_azul linkFake espacoDireita"  >Inserir</button>
                            </div>
                            <div>
                                <button className="div-botao borda_vermelha linkFake" >Cancelar</button>
                            </div>  
                        </div>
                    </div>
                </form>
            </fieldset>
        </div>
    )
}

export default NovoCliente;
